def _databricks_ai_model_context_to_nested(
    databricks_ai_model_context: DatabricksAIModelContext,
) -> DatabricksAIModelContextNested:
    """Convert flat DatabricksAIModelContext to nested format."""
    attrs = DatabricksAIModelContextAttributes()
    _populate_databricks_ai_model_context_attrs(attrs, databricks_ai_model_context)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        databricks_ai_model_context,
        _DATABRICKS_AI_MODEL_CONTEXT_REL_FIELDS,
        DatabricksAIModelContextRelationshipAttributes,
    )
    return DatabricksAIModelContextNested(
        guid=databricks_ai_model_context.guid,
        type_name=databricks_ai_model_context.type_name,
        status=databricks_ai_model_context.status,
        version=databricks_ai_model_context.version,
        create_time=databricks_ai_model_context.create_time,
        update_time=databricks_ai_model_context.update_time,
        created_by=databricks_ai_model_context.created_by,
        updated_by=databricks_ai_model_context.updated_by,
        classifications=databricks_ai_model_context.classifications,
        classification_names=databricks_ai_model_context.classification_names,
        meanings=databricks_ai_model_context.meanings,
        labels=databricks_ai_model_context.labels,
        business_attributes=databricks_ai_model_context.business_attributes,
        custom_attributes=databricks_ai_model_context.custom_attributes,
        pending_tasks=databricks_ai_model_context.pending_tasks,
        proxy=databricks_ai_model_context.proxy,
        is_incomplete=databricks_ai_model_context.is_incomplete,
        provenance_type=databricks_ai_model_context.provenance_type,
        home_id=databricks_ai_model_context.home_id,
        depth=databricks_ai_model_context.depth,
        immediate_upstream=databricks_ai_model_context.immediate_upstream,
        immediate_downstream=databricks_ai_model_context.immediate_downstream,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _databricks_ai_model_context_from_nested(
    nested: DatabricksAIModelContextNested,
) -> DatabricksAIModelContext:
    """Convert nested format to flat DatabricksAIModelContext."""
    attrs = (
        nested.attributes
        if nested.attributes is not UNSET
        else DatabricksAIModelContextAttributes()
    )
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _DATABRICKS_AI_MODEL_CONTEXT_REL_FIELDS,
        DatabricksAIModelContextRelationshipAttributes,
    )
    return DatabricksAIModelContext(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        depth=nested.depth,
        immediate_upstream=nested.immediate_upstream,
        immediate_downstream=nested.immediate_downstream,
        **_extract_databricks_ai_model_context_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _databricks_ai_model_context_to_nested_bytes(
    databricks_ai_model_context: DatabricksAIModelContext, serde: Serde
) -> bytes:
    """Convert flat DatabricksAIModelContext to nested JSON bytes."""
    return serde.encode(
        _databricks_ai_model_context_to_nested(databricks_ai_model_context)
    )


def _databricks_ai_model_context_from_nested_bytes(
    data: bytes, serde: Serde
) -> DatabricksAIModelContext:
    """Convert nested JSON bytes to flat DatabricksAIModelContext."""
    nested = serde.decode(data, DatabricksAIModelContextNested)
    return _databricks_ai_model_context_from_nested(nested)


